def _git_capture(repo_root: Path, args: Sequence[str], *, timeout_s: float = 10.0) -> dict[str, Any]:
    """Run a read-only git command and return a JSON-safe result."""

    try:
        completed = subprocess.run(
            ["git", "-C", str(repo_root), *args],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=timeout_s,
            check=False,
        )
    except Exception as exc:
        return {
            "ok": False,
            "returncode": None,
            "stdout": "",
            "stderr": str(exc),
            "args": list(args),
        }
    return {
        "ok": completed.returncode == 0,
        "returncode": completed.returncode,
        "stdout": completed.stdout or "",
        "stderr": completed.stderr or "",
        "args": list(args),
    }


def _git_stdout_lines(result: Mapping[str, Any], *, limit: int | None = None) -> list[str]:
    lines = [line.rstrip("\n") for line in str(result.get("stdout") or "").splitlines()]
    if limit is not None and len(lines) > limit:
        return lines[:limit]
    return lines


def _git_commit(repo_root: Path, ref: str) -> str:
    result = _git_capture(repo_root, ["rev-parse", "--verify", f"{ref}^{{commit}}"])
    if not result.get("ok"):
        return ""
    return str(result.get("stdout") or "").strip()


def _git_short_remote_head(repo_root: Path) -> str:
    result = _git_capture(repo_root, ["symbolic-ref", "--quiet", "--short", "refs/remotes/origin/HEAD"])
    if not result.get("ok"):
        return ""
    return str(result.get("stdout") or "").strip()


def _select_hub_remote_main_ref(repo_root: Path) -> dict[str, Any]:
    symbolic = _git_short_remote_head(repo_root)
    candidates: list[str] = []
    if symbolic:
        candidates.append(symbolic)
    candidates.extend(ALLFATHER_HUB_REMOTE_MAIN_REF_CANDIDATES)

    seen: set[str] = set()
    attempts: list[dict[str, Any]] = []
    for candidate in candidates:
        ref = str(candidate or "").strip()
        if not ref or ref in seen:
            continue
        seen.add(ref)
        commit = _git_commit(repo_root, ref)
        attempts.append({"ref": ref, "commit": commit, "ok": bool(commit)})
        if commit:
            return {"ok": True, "ref": ref, "commit": commit, "attempts": attempts}
    return {"ok": False, "ref": "", "commit": "", "attempts": attempts}


def _parse_ahead_behind(text: str) -> dict[str, int | None]:
    parts = str(text or "").strip().split()
    if len(parts) < 2:
        return {"ahead": None, "behind": None}
    try:
        return {"ahead": int(parts[1]), "behind": int(parts[0])}
    except ValueError:
        return {"ahead": None, "behind": None}


def allfather_hub_remote_manifest(repo_root: Path = REPO_ROOT) -> dict[str, Any]:
    """Describe the local checkout embedded into the remote Hub runtime.

    The all-father super-node image is built from the operator's current working
    tree, not from an implicit clean clone on the remote host.  This manifest is
    embedded beside ``main_computer.hub`` so the remote Hub can report whether
    the runtime came from a dirty local directory and how that directory compared
    with the selected remote main ref at build time.
    """

    generated_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat()
    root_result = _git_capture(repo_root, ["rev-parse", "--show-toplevel"])
    git_available = bool(root_result.get("ok"))
    git_root = str(root_result.get("stdout") or "").strip() if git_available else ""

    status_result = _git_capture(repo_root, ["status", "--porcelain=v1", "--untracked-files=all"]) if git_available else {
        "ok": False,
        "stdout": "",
        "stderr": str(root_result.get("stderr") or "git repository not available"),
    }
    status_entries = _git_stdout_lines(status_result, limit=ALLFATHER_HUB_REMOTE_MANIFEST_MAX_STATUS)
    status_truncated = len(_git_stdout_lines(status_result)) > len(status_entries)
    current_directory_dirty = bool(status_entries)

    head_commit = _git_commit(repo_root, "HEAD") if git_available else ""
    remote_selection = _select_hub_remote_main_ref(repo_root) if git_available else {
        "ok": False,
        "ref": "",
        "commit": "",
        "attempts": [],
    }
    remote_ref = str(remote_selection.get("ref") or "")
    remote_commit = str(remote_selection.get("commit") or "")

    if remote_ref:
        diff_result = _git_capture(
            repo_root,
            ["diff", "--name-status", remote_ref, "--"],
        )
        diff_entries = _git_stdout_lines(diff_result, limit=ALLFATHER_HUB_REMOTE_MANIFEST_MAX_DIFF)
        diff_truncated = len(_git_stdout_lines(diff_result)) > len(diff_entries)
        rev_list_result = _git_capture(repo_root, ["rev-list", "--left-right", "--count", f"{remote_ref}...HEAD"])
        ahead_behind = _parse_ahead_behind(str(rev_list_result.get("stdout") or ""))
    else:
        diff_result = {"ok": False, "stdout": "", "stderr": "remote main ref not available"}
        diff_entries = []
        diff_truncated = False
        ahead_behind = {"ahead": None, "behind": None}

    current_directory_dirty_vs_remote_main = bool(current_directory_dirty or diff_entries)

    manifest = {
        "kind": "main_computer.allfather.hub_remote_manifest.v1",
        "generated_at": generated_at,
        "repository": {
            "local_root": git_root or display_path(repo_root),
            "git_available": git_available,
            "head_commit": head_commit,
            "selected_remote_main_ref": remote_ref,
            "selected_remote_main_commit": remote_commit,
            "remote_main_selection": remote_selection,
        },
        "observed": {
            "current_directory_dirty_in_hub_remote_manifest": current_directory_dirty,
            "current_directory_compared_to_remote_main": bool(remote_ref),
            "remote_main_ref_selected": bool(remote_ref),
        },
        "working_tree": {
            "dirty": current_directory_dirty,
            "status_porcelain_v1": status_entries,
            "status_entry_count": len(_git_stdout_lines(status_result)),
            "status_truncated": status_truncated,
            "status_ok": bool(status_result.get("ok")),
            "status_error": str(status_result.get("stderr") or "").strip(),
        },
        "comparison": {
            "basis": "selected-remote-main-ref-vs-current-working-tree",
            "selected_remote_main_ref": remote_ref,
            "selected_remote_main_commit": remote_commit,
            "head_commit": head_commit,
            "ahead": ahead_behind["ahead"],
            "behind": ahead_behind["behind"],
            "current_directory_dirty_vs_remote_main": current_directory_dirty_vs_remote_main,
            "diff_name_status": diff_entries,
            "diff_entry_count": len(_git_stdout_lines(diff_result)),
            "diff_truncated": diff_truncated,
            "diff_ok": bool(diff_result.get("ok")),
            "diff_error": str(diff_result.get("stderr") or "").strip(),
        },
        "notes": [
            "This manifest is generated by allfather while building the embedded Hub runtime archive.",
            "It records the operator checkout that is shipped to the remote Hub image.",
            "A dirty current directory is intentional evidence that the remote Hub is not just reporting origin/main.",
        ],
    }
    return manifest


def _zip_writestr_deterministic(archive: zipfile.ZipFile, arcname: str, data: bytes) -> None:
    info = zipfile.ZipInfo(arcname)
    info.date_time = (2020, 1, 1, 0, 0, 0)
    archive.writestr(info, data, compress_type=zipfile.ZIP_DEFLATED)


def allfather_contract_sources_b64() -> dict[str, str]:
    """Return contract sources embedded into the self-contained super-node image."""

    payload: dict[str, str] = {}
    for contract_path, source_path in ALLFATHER_CONTRACT_SOURCE_FILES.items():
        payload[contract_path] = base64.b64encode(source_path.read_text(encoding="utf-8").encode("utf-8")).decode("ascii")
    return payload


def allfather_full_hub_runtime_archive_b64() -> str:
    """Return compressed zip payload for the full Main Computer hub runtime.

    The inline Coolify super-node image cannot assume the operator's checkout is
    mounted on the Docker host.  Hub propagation therefore embeds the hub runtime
    source needed by ``main_computer.hub`` into the rebuilt super-node image.
    """

    package_root = REPO_ROOT / "main_computer"
    buffer = io.BytesIO()
    written: set[str] = set()
    with zipfile.ZipFile(buffer, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        for rel_name in ALLFATHER_FULL_HUB_RUNTIME_FILES:
            source = package_root / rel_name
            if not source.exists() or not source.is_file():
                raise AllfatherControlError(f"Full hub runtime source file is missing: {source}")
            arcname = f"main_computer/{rel_name.replace(chr(92), '/')}"
            _zip_writestr_deterministic(archive, arcname, source.read_bytes())
            written.add(arcname)
        manifest = allfather_hub_remote_manifest(REPO_ROOT)
        manifest_bytes = (json.dumps(manifest, sort_keys=True, indent=2) + "\n").encode("utf-8")
        _zip_writestr_deterministic(archive, ALLFATHER_HUB_REMOTE_MANIFEST_ARCNAME, manifest_bytes)
        written.add(ALLFATHER_HUB_REMOTE_MANIFEST_ARCNAME)
        config_dir = package_root / "config"
        for source in sorted(config_dir.glob("*.json")):
            arcname = f"main_computer/config/{source.name}"
            if arcname in written:
                continue
            _zip_writestr_deterministic(archive, arcname, source.read_bytes())
            written.add(arcname)
    return base64.b64encode(zlib.compress(buffer.getvalue())).decode("ascii")


def allfather_contract_artifact_builder_script() -> str:
    """Return the build-context script that compiles all-father Solidity artifacts once.

    The managed super-base builder writes this script into the Docker build context.
    The resulting base image contains /opt/allfather-contracts/contracts-artifacts.json,
    so runtime add-node resumes do not keep invoking solc inside the live super-node.
    """

    return r"""
from __future__ import annotations
import base64
import json
import os
import subprocess
import sys
from pathlib import Path

REQUIRED_TARGETS = (
    ("AlphaBetaLockout.sol", "AlphaBetaLockout"),
    ("src/XLagBridgeReserve.sol", "XLagBridgeReserve"),
    ("src/HubCreditBridgeEscrow.sol", "HubCreditBridgeEscrow"),
)

CONTRACT_EVM_VERSION = os.environ.get("MC_ALLFATHER_CONTRACT_EVM_VERSION", "paris").strip() or "paris"

def bytecode_contains_opcode(bytecode: str, opcode: int) -> bool:
    text = str(bytecode or "").strip()
    if text.startswith("0x"):
        text = text[2:]
    if len(text) % 2:
        return False
    try:
        data = bytes.fromhex(text)
    except ValueError:
        return False
    i = 0
    while i < len(data):
        value = data[i]
        if value == opcode:
            return True
        if 0x60 <= value <= 0x7f:
            i += 1 + (value - 0x5f)
        else:
            i += 1
    return False

def bytecode_contains_push0(bytecode: str) -> bool:
    return bytecode_contains_opcode(bytecode, 0x5f)

def artifact_is_valid(compiled: dict) -> bool:
    contracts = compiled.get("contracts")
    if not isinstance(contracts, dict):
        return False
    for source_name, contract_name in REQUIRED_TARGETS:
        contract = ((contracts.get(source_name) or {}).get(contract_name) or {})
        bytecode = (((contract.get("evm") or {}).get("bytecode") or {}).get("object") or "")
        abi = contract.get("abi")
        if not isinstance(abi, list) or not str(bytecode).strip():
            return False
        if bytecode_contains_push0(bytecode):
            return False
    return True

def main() -> int:
    source_path = Path(sys.argv[1])
    output_path = Path(sys.argv[2])
    sources_b64 = json.loads(source_path.read_text(encoding="utf-8"))
    sources = {
        name: {"content": base64.b64decode(encoded).decode("utf-8")}
        for name, encoded in sources_b64.items()
    }
    standard_input = {
        "language": "Solidity",
        "sources": sources,
        "settings": {
            "evmVersion": CONTRACT_EVM_VERSION,
            "optimizer": {"enabled": True, "runs": 200},
            "outputSelection": {"*": {"*": ["abi", "evm.bytecode.object"]}},
        },
    }
    proc = subprocess.run(
        ["solc", "--standard-json"],
        input=json.dumps(standard_input),
        text=True,
        capture_output=True,
        timeout=180,
        check=False,
    )
    if proc.returncode != 0:
        sys.stderr.write((proc.stderr or proc.stdout or "solc --standard-json failed").strip() + "\n")
        return proc.returncode or 1
    compiled = json.loads(proc.stdout or "{}")
    errors = [
        item
        for item in compiled.get("errors", [])
        if isinstance(item, dict) and item.get("severity") == "error"
    ]
    if errors:
        sys.stderr.write("; ".join(str(item.get("formattedMessage") or item.get("message") or item) for item in errors) + "\n")
        return 1
    if not artifact_is_valid(compiled):
        sys.stderr.write("compiled all-father contract artifact set is incomplete or contains PUSH0 for a pre-Shanghai chain\n")
        return 1
    compiled.setdefault("x-allfather", {})["contractEvmVersion"] = CONTRACT_EVM_VERSION
    compiled.setdefault("x-allfather", {})["push0Forbidden"] = True
    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.write_text(json.dumps(compiled, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    print(f"compiled all-father contract artifacts: {output_path}")
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
""".lstrip()



class AllfatherControlError(ValueError):
    """Raised when the all-father control surface cannot be planned or applied."""


@dataclass(frozen=True)
class CoolifyHostSeed:
    slot: str
    name: str
    url: str = ""
    guard_host: str = ""
    public_ip: str = ""
    vpn_ip: str = ""
    token_source: str = ""
    metadata: dict[str, Any] | None = None

    def publish_host(self) -> str:
        return self.guard_host or self.vpn_ip or self.public_ip or ""


@dataclass(frozen=True)
class HeadNode:
    head_id: str
    service_name: str
    coolify_server: str
    slot: str
    guard_container_port: int
    guard_host_port: int
    guard_publish_host: str
    guard_url: str
    state_root: str
    peers: tuple[dict[str, Any], ...]

    def peer_summary(self) -> list[dict[str, Any]]:
        return [dict(peer) for peer in self.peers]


@dataclass(frozen=True)
class HeadPlan:
    kind: str
    private_state_path: str
    heads: tuple[HeadNode, ...]
    desired_counts: dict[str, int]
    guardrails: dict[str, Any]

    def to_dict(self, *, include_compose: bool = False, dockerfile: str = DEFAULT_DOCKERFILE, image: str = DEFAULT_IMAGE) -> dict[str, Any]:
        heads_payload: list[dict[str, Any]] = []
        for head in self.heads:
            payload = asdict(head)
            payload["peers"] = head.peer_summary()
            payload["manifest"] = head_manifest(self, head)
            payload["compose"] = render_head_compose(self, head, dockerfile=dockerfile, image=image) if include_compose else None
            if not include_compose:
                payload.pop("compose", None)
            heads_payload.append(payload)
        return {
            "kind": self.kind,
            "private_state_path": self.private_state_path,
            "desired_counts": dict(self.desired_counts),
            "guardrails": dict(self.guardrails),
            "heads": heads_payload,
            "topology": {
                "source": "coolify-host-seed-only",
                "discovery_mode": "allfather-head-peer-advertise-v1",
                "guard_urls": [head.guard_url for head in self.heads],
                "note": (
                    "This is only the all-father control surface. It does not infer "
                    "or deploy mainnet/testnet Hub, FDB, QBFT, hub_admin, or contracts."
                ),
            },
        }


def _load_module(name: str, path: Path) -> Any:
    if name in sys.modules:
        return sys.modules[name]
    spec = importlib.util.spec_from_file_location(name, path)
    if spec is None or spec.loader is None:
        raise AllfatherControlError(f"Could not import {path}")
    module = importlib.util.module_from_spec(spec)
    sys.modules[spec.name] = module
    spec.loader.exec_module(module)
    return module


def fdb_tool() -> Any:
    return _load_module("coolify_fdb_cluster_for_allfather_control", FDB_CLUSTER_TOOL_PATH)


def hub_service_tool() -> Any:
    return _load_module("coolify_hub_service_for_allfather_control", HUB_SERVICE_TOOL_PATH)


def repo_relative_path(raw: str | Path) -> Path:
    path = Path(raw).expanduser()
    if path.is_absolute():
        return path
    return REPO_ROOT / path


def display_path(path: Path) -> str:
    try:
        return str(path.relative_to(REPO_ROOT))
    except ValueError:
        return str(path)


def safe_id(value: str, *, field: str = "id") -> str:
    clean = re.sub(r"[^a-zA-Z0-9_.-]+", "-", str(value or "").strip()).strip("-").lower()
    if not clean:
        raise AllfatherControlError(f"{field} must not be empty.")
    if clean.startswith(".") or ".." in clean:
        raise AllfatherControlError(f"{field} contains an unsafe path-like value: {value!r}")
    return clean


def sanitize_fdb_cluster_description(value: str) -> str:
    """Return a FoundationDB cluster-file description token.

    FoundationDB cluster file descriptions may use alphanumeric characters and
    underscores.  Do not reuse the more permissive service-name sanitizer here:
    hyphens make fdbcli reject the cluster file as an invalid connection string.
    """

    clean = re.sub(r"[^A-Za-z0-9_]+", "_", str(value or "").strip())
    clean = re.sub(r"_+", "_", clean).strip("_")
    if not clean:
        clean = "main_computer_allfather"
    if not FDB_CLUSTER_DESCRIPTION_RE.match(clean):
        raise AllfatherControlError(f"Could not build a valid FoundationDB cluster description from {value!r}.")
    return clean


def fdb_cluster_description_for_network(network_key: str) -> str:
    return sanitize_fdb_cluster_description(f"main_computer_{clean_node_network_key(network_key)}_allfather")


def docker_container_name_token(value: str) -> str:
    clean = re.sub(r"[^a-zA-Z0-9_.-]+", "-", str(value or "").strip()).strip("-").lower()
    clean = re.sub(r"-+", "-", clean)
    return clean or "allfather-super"


def super_container_name_from_manifest(manifest: Mapping[str, Any]) -> str:
    """Return the stable Docker name that public Hub routes target.

    Hub propagation writes Traefik backends such as ``http://mainneta-super1:8785``.
    The service container name therefore must remain stable across rebuilds.  The
    deployment id is carried in labels/environment/build files for cache busting
    and diagnostics, not in the Docker container name; otherwise Coolify can start
    a healthy rebuilt container while Traefik continues to hit the old bootstrap
    container.
    """

    return docker_container_name_token(str(manifest.get("cell_id") or "allfather-super"))[:120].rstrip("-.")


def new_super_deployment_id() -> str:
    return f"{int(time.time())}-{secrets.token_hex(4)}"


def host_slot_index(slot: str) -> int:
    clean = str(slot or "").strip().upper()
    if len(clean) == 1 and "A" <= clean <= "Z":
        return ord(clean) - ord("A")
    try:
        return max(0, int(clean) - 1)
    except Exception:
        return 0


def super_base_builder_service_name(head: HeadNode) -> str:
    return f"{DEFAULT_SUPER_BASE_BUILDER_PREFIX}-{docker_container_name_token(head.coolify_server or head.slot or 'host')}"


def super_base_builder_host_port(head: HeadNode) -> int:
    return DEFAULT_SUPER_BASE_BUILDER_HOST_BASE + host_slot_index(head.slot)


def super_base_builder_url(head: HeadNode) -> str:
    host = str(head.guard_publish_host or "").strip()
    if not host:
        return ""
    return f"http://{host}:{super_base_builder_host_port(head)}"


def super_runtime_cleanup_service_name(network_key: str, head: HeadNode) -> str:
    return (
        f"{DEFAULT_SUPER_RUNTIME_CLEANUP_PREFIX}-"
        f"{clean_node_network_key(network_key)}-"
        f"{docker_container_name_token(head.coolify_server or head.slot or 'host')}"
    )


def super_runtime_cleanup_host_port(network_key: str, head: HeadNode) -> int:
    network_offset = 100 if clean_node_network_key(network_key) == "mainnet" else 0
    return DEFAULT_SUPER_RUNTIME_CLEANUP_HOST_BASE + network_offset + host_slot_index(head.slot)


def super_runtime_cleanup_url(network_key: str, head: HeadNode) -> str:
    host = str(head.guard_publish_host or "").strip()
    if not host:
        return ""
    return f"http://{host}:{super_runtime_cleanup_host_port(network_key, head)}"


def shell_single_quote(value: Any) -> str:
    return "'" + str(value).replace("'", "'\''") + "'"


def private_value(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        text = value.strip()
        if not text or PRIVATE_PLACEHOLDER_RE.match(text):
            return ""
        return text
    return str(value).strip()


def load_yaml_mapping(path: Path) -> dict[str, Any]:
    try:
        import yaml
    except ImportError as exc:  # pragma: no cover - PyYAML is present in the project test env.
        raise AllfatherControlError("PyYAML is required to read all-father private state YAML.") from exc

    if not path.exists():
        raise AllfatherControlError(f"All-father private state file does not exist: {display_path(path)}")
    try:
        loaded = yaml.safe_load(path.read_text(encoding="utf-8"))
    except Exception as exc:
        raise AllfatherControlError(f"Could not read or parse {display_path(path)}: {exc}") from exc

    if not isinstance(loaded, dict):
        raise AllfatherControlError(f"All-father private state must contain a YAML mapping: {display_path(path)}")
    return loaded




def dump_yaml_mapping(state: Mapping[str, Any]) -> str:
    try:
        import yaml
    except ImportError as exc:  # pragma: no cover - PyYAML is present in the project test env.
        raise AllfatherControlError("PyYAML is required to write all-father private state YAML.") from exc

    return yaml.safe_dump(dict(state), sort_keys=False, allow_unicode=True)


def write_yaml_mapping(path: Path, state: Mapping[str, Any]) -> None:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(dump_yaml_mapping(state), encoding="utf-8")
    except OSError as exc:
        raise AllfatherControlError(f"Could not write all-father private state file {display_path(path)}: {exc}") from exc


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def generated_private_key() -> str:
    # Ethereum private keys are 32-byte secp256k1 scalars.  Addresses are
    # derived locally when the key is materialized into private state.
    while True:
        key = "0x" + secrets.token_hex(32)
        if int(key[2:], 16) != 0:
            return key


# secp256k1 / Keccak helpers kept local so hub-propagate can materialize
# Hub admin addresses before any runtime or contract-sync step.  Do not use
# hashlib.sha3_256 here: Ethereum uses Keccak-256 padding, not FIPS SHA3.
_SECP256K1_P = 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEFFFFFC2F
_SECP256K1_N = 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141
_SECP256K1_G = (
    55066263022277343669578718895168534326250603453777594175500187360389116729240,
    32670510020758816978083085130507043184471273380659243275938904335757337482424,
)
_KECCAK_ROUNDS = (
    0x0000000000000001,
    0x0000000000008082,
    0x800000000000808A,
    0x8000000080008000,
    0x000000000000808B,
    0x0000000080000001,
    0x8000000080008081,
    0x8000000000008009,
    0x000000000000008A,
    0x0000000000000088,
    0x0000000080008009,
    0x000000008000000A,
    0x000000008000808B,
    0x800000000000008B,
    0x8000000000008089,
    0x8000000000008003,
    0x8000000000008002,
    0x8000000000000080,
    0x000000000000800A,
    0x800000008000000A,
    0x8000000080008081,
    0x8000000000008080,
    0x0000000080000001,
    0x8000000080008008,
)
_KECCAK_ROTATION = (
    (0, 36, 3, 41, 18),
    (1, 44, 10, 45, 2),
    (62, 6, 43, 15, 61),
    (28, 55, 25, 21, 56),
    (27, 20, 39, 8, 14),
)


def _rotl64(value: int, shift: int) -> int:
    shift %= 64
    return ((value << shift) | (value >> (64 - shift))) & 0xFFFFFFFFFFFFFFFF


def _keccak_f1600(state: list[int]) -> None:
    for rc in _KECCAK_ROUNDS:
        c = [state[x] ^ state[x + 5] ^ state[x + 10] ^ state[x + 15] ^ state[x + 20] for x in range(5)]
        d = [c[(x - 1) % 5] ^ _rotl64(c[(x + 1) % 5], 1) for x in range(5)]
        for x in range(5):
            for y in range(5):
                state[x + 5 * y] ^= d[x]
        b = [0] * 25
        for x in range(5):
            for y in range(5):
                b[y + 5 * ((2 * x + 3 * y) % 5)] = _rotl64(state[x + 5 * y], _KECCAK_ROTATION[x][y])
        for x in range(5):
            for y in range(5):
                state[x + 5 * y] = b[x + 5 * y] ^ ((~b[((x + 1) % 5) + 5 * y]) & b[((x + 2) % 5) + 5 * y])
        state[0] ^= rc


def keccak256(data: bytes) -> bytes:
    rate = 136
    state = [0] * 25
    offset = 0
    while offset + rate <= len(data):
        block = data[offset : offset + rate]
        for index in range(rate // 8):
            state[index] ^= int.from_bytes(block[index * 8 : (index + 1) * 8], "little")
        _keccak_f1600(state)
        offset += rate
    block = bytearray(rate)
    remainder = data[offset:]
    block[: len(remainder)] = remainder
    block[len(remainder)] ^= 0x01
    block[-1] ^= 0x80
    for index in range(rate // 8):
        state[index] ^= int.from_bytes(block[index * 8 : (index + 1) * 8], "little")
    _keccak_f1600(state)
    out = bytearray()
    while len(out) < 32:
        for index in range(rate // 8):
            out.extend(state[index].to_bytes(8, "little"))
            if len(out) >= 32:
                break
        if len(out) < 32:
            _keccak_f1600(state)
    return bytes(out[:32])


def _secp256k1_inverse(value: int) -> int:
    return pow(value % _SECP256K1_P, _SECP256K1_P - 2, _SECP256K1_P)


def _secp256k1_add(
    point_a: tuple[int, int] | None,
    point_b: tuple[int, int] | None,
) -> tuple[int, int] | None:
    if point_a is None:
        return point_b
    if point_b is None:
        return point_a
    x1, y1 = point_a
    x2, y2 = point_b
    if x1 == x2 and (y1 + y2) % _SECP256K1_P == 0:
        return None
    if point_a == point_b:
        slope = (3 * x1 * x1) * _secp256k1_inverse(2 * y1)
    else:
        slope = (y2 - y1) * _secp256k1_inverse(x2 - x1)
    slope %= _SECP256K1_P
    x3 = (slope * slope - x1 - x2) % _SECP256K1_P
    y3 = (slope * (x1 - x3) - y1) % _SECP256K1_P
    return x3, y3


def _secp256k1_multiply(scalar: int) -> tuple[int, int]:
    if not (1 <= scalar < _SECP256K1_N):
        raise AllfatherControlError("Ethereum private key is outside the valid secp256k1 range")
    result: tuple[int, int] | None = None
    addend: tuple[int, int] | None = _SECP256K1_G
    while scalar:
        if scalar & 1:
            result = _secp256k1_add(result, addend)
        addend = _secp256k1_add(addend, addend)
        scalar >>= 1
    if result is None:
        raise AllfatherControlError("Ethereum private key derived the point at infinity")
    return result


def normalize_ethereum_private_key(private_key: Any) -> str:
    raw = nonempty_private_value(private_key)
    if raw.startswith(("0x", "0X")):
        raw = raw[2:]
    if not re.fullmatch(r"[0-9a-fA-F]{64}", raw):
        raise AllfatherControlError("Ethereum private key must be 32 bytes hex")
    value = int(raw, 16)
    if not (1 <= value < _SECP256K1_N):
        raise AllfatherControlError("Ethereum private key is outside the valid secp256k1 range")
    return "0x" + raw.lower()


def checksum_ethereum_address(address_hex: str) -> str:
    raw = str(address_hex or "").strip().lower()
    if raw.startswith("0x"):
        raw = raw[2:]
    if not re.fullmatch(r"[0-9a-f]{40}", raw):
        raise AllfatherControlError("Ethereum address must be 20 bytes hex")
    digest = keccak256(raw.encode("ascii")).hex()
    checked = "".join(ch.upper() if int(digest[index], 16) >= 8 else ch for index, ch in enumerate(raw))
    return "0x" + checked


def ethereum_address_from_private_key(private_key: Any) -> str:
    normalized = normalize_ethereum_private_key(private_key)
    scalar = int(normalized[2:], 16)
    x, y = _secp256k1_multiply(scalar)
    public_key = x.to_bytes(32, "big") + y.to_bytes(32, "big")
    return checksum_ethereum_address(keccak256(public_key)[-20:].hex())


def generated_cluster_id() -> str:
    return secrets.token_hex(8)


def nonempty_private_value(value: Any) -> str:
    raw = str(value or "").strip()
    if not raw or PRIVATE_PLACEHOLDER_RE.match(raw):
        return ""
    return raw

def _host_field(payload: Mapping[str, Any], names: Iterable[str]) -> str:
    for name in names:
        value = private_value(payload.get(name))
        if value:
            return value
    return ""


def _token_source(slot: str, payload: Mapping[str, Any]) -> str:
    for key in ("api_token", "token", "coolify_token"):
        if private_value(payload.get(key)):
            return f"private-state:coolify.hosts.{slot}.{key}"
    for key in ("api_token_env", "token_env", "coolify_token_env"):
        value = private_value(payload.get(key))
        if value:
            return f"private-state:coolify.hosts.{slot}.{key}->env:{value}"
    for key in ("api_token_file", "token_file", "coolify_token_file"):
        value = private_value(payload.get(key))
        if value:
            return f"private-state:coolify.hosts.{slot}.{key}->file:{value}"
    return ""


def coolify_hosts_from_private_state(state: Mapping[str, Any]) -> list[CoolifyHostSeed]:
    coolify = state.get("coolify")
    if not isinstance(coolify, Mapping):
        raise AllfatherControlError("all_father.private.yaml must contain a top-level coolify mapping.")

    hosts_payload = coolify.get("hosts")
    if not isinstance(hosts_payload, Mapping) or not hosts_payload:
        raise AllfatherControlError("all_father.private.yaml must contain coolify.hosts entries.")

    hosts: list[CoolifyHostSeed] = []
    seen: set[str] = set()
    for slot, payload in hosts_payload.items():
        if not isinstance(payload, Mapping):
            continue
        name = _host_field(payload, ("name", "server", "server_name", "coolify_server"))
        if not name:
            continue
        name = safe_id(name, field=f"coolify.hosts.{slot}.name")
        if name in seen:
            raise AllfatherControlError(f"Duplicate Coolify host name in all-father private state: {name}")
        seen.add(name)
        hosts.append(
            CoolifyHostSeed(
                slot=str(slot),
                name=name,
                url=_host_field(payload, ("url", "api_url", "coolify_url", "base_url")),
                guard_host=_host_field(payload, ("guard_host", "guard_publish_host", "allfather_guard_host")),
                public_ip=_host_field(payload, ("public_ip", "ip", "host_ip")),
                vpn_ip=_host_field(payload, ("vpn_ip", "private_ip", "tailscale_ip", "zerotier_ip")),
                token_source=_token_source(str(slot), payload),
                metadata={
                    key: value
                    for key, value in payload.items()
                    if key
                    in {
                        "uuid",
                        "server_uuid",
                        "destination_uuid",
                        "environment_uuid",
                        "project_uuid",
                        "project_name",
                    }
                },
            )
        )

    if not hosts:
        raise AllfatherControlError("No usable Coolify hosts were found in coolify.hosts.")
    return sorted(hosts, key=lambda host: host.name)


def load_private_hosts(path: Path) -> list[CoolifyHostSeed]:
    return coolify_hosts_from_private_state(load_yaml_mapping(path))


def guard_url_for_host(host: CoolifyHostSeed, guard_port: int) -> str:
    target = host.publish_host() or host.name
    return f"http://{target}:{guard_port}"


def build_head_plan(
    hosts: Sequence[CoolifyHostSeed],
    *,
    private_state_path: Path,
    guard_host_base: int = DEFAULT_GUARD_HOST_BASE,
    guard_container_port: int = DEFAULT_GUARD_CONTAINER_PORT,
    state_root_prefix: str = DEFAULT_STATE_ROOT_PREFIX,
    image: str = DEFAULT_IMAGE,
) -> HeadPlan:
    if not hosts:
        raise AllfatherControlError("At least one Coolify host is required to bootstrap all-father heads.")

    raw_heads: list[dict[str, Any]] = []
    for index, host in enumerate(sorted(hosts, key=lambda item: item.name)):
        host_port = guard_host_base + index
        raw_heads.append(
            {
                "head_id": safe_id(f"allfather-head-{host.name}", field="head_id"),
                "service_name": safe_id(f"{DEFAULT_SERVICE_PREFIX}-{host.name}", field="service_name"),
                "coolify_server": host.name,
                "slot": host.slot,
                "guard_container_port": guard_container_port,
                "guard_host_port": host_port,
                "guard_publish_host": host.publish_host(),
                "guard_url": guard_url_for_host(host, host_port),
                "state_root": f"{state_root_prefix.rstrip('/')}/{host.name}",
            }
        )

    heads: list[HeadNode] = []
    for raw in raw_heads:
        peers = tuple(
            {
                "head_id": peer["head_id"],
                "coolify_server": peer["coolify_server"],
                "guard_host_port": peer["guard_host_port"],
                "guard_publish_host": peer["guard_publish_host"],
                "guard_url": peer["guard_url"],
                "state_root": peer["state_root"],
            }
            for peer in raw_heads
            if peer["head_id"] != raw["head_id"]
        )
        heads.append(HeadNode(**raw, peers=peers))

    return HeadPlan(
        kind="main_computer.allfather_control_plane_plan.v1",
        private_state_path=display_path(private_state_path),
        heads=tuple(heads),
        desired_counts={
            "allfather_heads": len(heads),
            "super_nodes": 0,
            "foundationdb": 0,
            "hub": 0,
            "qbft_validator_rpc": 0,
            "hub_admin": 0,
            "contracts": 0,
        },
        guardrails={
            "private_state_is_topology": False,
            "topology_source": "live-coolify-and-guard-discovery",
            "hub_admin_requires_live_qbft_validator_rpc": True,
            "contracts_require_live_qbft_validator_rpc": True,
            "hub_public_cutover_requires_live_qbft_validator_rpc": True,
            "bootstrap_heads_deploys_workloads": False,
        },
    )


def manifest_b64(manifest: Mapping[str, Any]) -> str:
    payload = json.dumps(manifest, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return base64.b64encode(payload).decode("ascii")


