def decode_json_b64(text, default):
    if not text:
        return default
    try:
        value = json.loads(base64.b64decode(text).decode("utf-8"))
        return value if value is not None else default
    except Exception as exc:
        return {"ok": False, "error": f"{type(exc).__name__}: {exc}"}

